def gen(rng, size):
    n = rng.randint(2, max(2, min(size, 400)))
    vals = rng.sample(range(1, 1000000), n)
    # build BST by insertion order, then serialize level-order with nulls
    class N:
        __slots__ = ('v', 'l', 'r')
        def __init__(self, v):
            self.v = v; self.l = None; self.r = None
    root = None
    def insert(root, v):
        if root is None:
            return N(v)
        cur = root
        while True:
            if v < cur.v:
                if cur.l is None:
                    cur.l = N(v); break
                cur = cur.l
            else:
                if cur.r is None:
                    cur.r = N(v); break
                cur = cur.r
        return root
    for v in vals:
        root = insert(root, v)
    # level-order serialize
    out = []
    q = [root]
    while q:
        node = q.pop(0)
        if node is None:
            out.append(None)
            continue
        out.append(node.v)
        q.append(node.l)
        q.append(node.r)
    while out and out[-1] is None:
        out.pop()
    qn = rng.randint(1, 200)
    queries = [rng.randint(1, 1000000) for _ in range(qn)]
    return [out, queries]

