class Solution:
    def closestNodes(self, root, queries):
        vals = []
        def inorder(node):
            if not node:
                return
            inorder(node.left)
            vals.append(node.val)
            inorder(node.right)
        inorder(root)
        res = []
        for q in queries:
            lo = -1
            hi = -1
            for v in vals:
                if v <= q and v > lo:
                    lo = v
            best_hi = None
            for v in vals:
                if v >= q and (best_hi is None or v < best_hi):
                    best_hi = v
            hi = best_hi if best_hi is not None else -1
            res.append([lo, hi])
        return res

