import bisect
class Solution:
    def closestNodes(self, root, queries):
        vals = []
        stack = []
        node = root
        while stack or node:
            while node:
                stack.append(node)
                node = node.left
            node = stack.pop()
            vals.append(node.val)
            node = node.right
        res = []
        for q in queries:
            i = bisect.bisect_left(vals, q)
            hi = vals[i] if i < len(vals) else -1
            if i < len(vals) and vals[i] == q:
                lo = q
            else:
                lo = vals[i - 1] if i - 1 >= 0 else -1
            res.append([lo, hi])
        return res

