var closestNodes = function(root, queries) {
    const vals = [];
    const stack = [];
    let node = root;
    while (stack.length || node) {
        while (node) { stack.push(node); node = node.left; }
        node = stack.pop();
        vals.push(node.val);
        node = node.right;
    }
    const lowerBound = (arr, x) => {
        let lo = 0, hi = arr.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (arr[mid] < x) lo = mid + 1; else hi = mid;
        }
        return lo;
    };
    const res = [];
    for (const q of queries) {
        const i = lowerBound(vals, q);
        const hi = i < vals.length ? vals[i] : -1;
        let lo;
        if (i < vals.length && vals[i] === q) lo = q;
        else lo = i - 1 >= 0 ? vals[i - 1] : -1;
        res.push([lo, hi]);
    }
    return res;
};
